int solve(int n)
{
    int i = 1;
    dp[0] = 0;
    dp[1] = 1;
    dp[2] = 1;
    if (n == 1) return 1;
    if (n == 2) return 1;
    if (dp[i] != -1) return dp[i];
    if (i < n) 
    {
        i++;
        dp[i] = solve(i-1)+solve(i-2);
    }
    else if ( i == n) return dp[i];
